using System.Collections;using System.Collections.Generic;using Newtonsoft.Json;using TMPro;using UnityEngine;using UnityEngine.UI;using UnityEngine.Networking;public class UISCript_DogBreed : MonoBehaviour{    //Content    public TextMeshProUGUI pageCountText;    public Button previousButton,  nextButton;    //API_Content    public Transform textContainer; //Canvas Position    public GameObject textPrefab; //para sa text    public const float spaceInText = 150f; //padding    //Camera    public Camera cam;    //pages    private List<string> allTexts = new List<string>();    private int contentPerPage = 10, currentPage = 10, totalPages = 0;    //dog pictures work!    // string URL = "https://dog.ceo/api/breeds/list/all";    //ok    string URL = "https://dogapi.dog/api/v2/breeds";    void Start()    {        //on click previoosu btn        previousButton.onClick.AddListener(PreviousPage);        //on clicks nex tbtn        nextButton.onClick.AddListener(NextPage);        //once click fetch aopi        StartCoroutine(FetchAPI());    }        IEnumerator FetchAPI()    {        UnityWebRequest request = UnityWebRequest.Get(URL);        yield return request.SendWebRequest();            if (request.result == UnityWebRequest.Result.ConnectionError ||            request.result == UnityWebRequest.Result.ProtocolError)        {            Debug.LogError(request.error);        }        else        {            string json = request.downloadHandler.text;            Debug.Log("API Response received");            var response = JsonConvert.DeserializeObject<DogApiResponse>(json);                    // Extract breed names from the data array            allTexts = new List<string>();            foreach (var breed in response.data)            {                allTexts.Add(breed.attributes.name);            }            totalPages = Mathf.CeilToInt((float)allTexts.Count / contentPerPage);            Debug.Log($"{allTexts.Count} breeds, {totalPages} pages");                    InstantiatePage();                    currentPage = totalPages - 1;            MoveCamToPage(currentPage);            CurrentPage();        }    }        //isntatiate page    private void InstantiatePage()    {        for (int i = 0; i < allTexts.Count; i++)        {            GameObject page = Instantiate(textPrefab, textContainer);            //call UI text            TextMeshPro pageText = page.GetComponent<TextMeshPro>();                    pageText.text = allTexts[i];            //pain            // RectTransform pageRect = page.GetComponent<RectTransform>();            // pageRect.anchoredPosition = new Vector3(0, -i * spaceInText, 0);                        page.transform.localPosition = new Vector3(0, -i * spaceInText, 0);            Debug.Log($"Breed {i} ({allTexts[i]}) positioned at Y: {-i * spaceInText}");                        page.name = "Current: " + allTexts[i];        }        Debug.Log($"Instantiated {allTexts.Count} breed objects");            }    //NextPage()    private void NextPage()    {        //once clicked page changed to the next segment        if (currentPage < totalPages - 1)        {            currentPage++;            MoveCamToPage(currentPage);            CurrentPage();        }    }    //PreviousPage()    private void PreviousPage()    {        //return to the previous current page        if (currentPage > 0)        {            currentPage--;            MoveCamToPage(currentPage);            CurrentPage();        }    }    //Count Clicked, CurrentPage()    private void CurrentPage()    {        pageCountText.text = $"{currentPage + 1} / {totalPages}";    }    //camera jumps to next or previous page, MoveCamToPage(int numPage)    private void MoveCamToPage(int pageNumber)    {        float translateY = -(pageNumber * contentPerPage * spaceInText) / 100f;        Debug.Log($"Moving camera to page {pageNumber}, Y position: {translateY}");        Vector3 camPos = new Vector3(cam.transform.position.x, translateY, cam.transform.position.z);        cam.transform.position = camPos;    }    }[System.Serializable]public class DogApiResponse{    public List<BreedData> data;}[System.Serializable]public class BreedData{    //frogot to call    public string id;    public string type;    public BreedAttributes attributes;}[System.Serializable]public class BreedAttributes{    public string name;    public string description;}